#!/usr/bin/env python3
import base64
import string

def is_printable(text):
    # Check if text contains mostly printable ASCII characters
    printable = 0
    for c in text:
        if chr(c) in string.printable:
            printable += 1
    return (printable / len(text)) > 0.8

def single_byte_xor(data, key):
    return bytes([b ^ key for b in data])

# Base64 encoded ciphertext
b64_str = ""

# Decode base64
ciphertext = base64.b64decode(b64_str)

print("Attempting single-byte XOR bruteforce...")
print("-" * 50)

# Try all possible single byte values
for key in range(256):
    result = single_byte_xor(ciphertext, key)

    # Check if result is mostly printable ASCII and contains interesting patterns
    if is_printable(result):
        try:
            decoded = result.decode('ascii', errors='ignore')
            if any(pattern in decoded.lower() for pattern in ['flag{', 'the ', ' the', 'and ', ' and', 'this']):
                print(f"\nKey 0x{key:02x} ({key}):")
                print(decoded)
                print("-" * 50)
        except UnicodeDecodeError:
            continue
